// src/services/mongodb.js
// Thin wrapper around realm-web for direct Atlas access from the browser.
// ──────────────────────────────────────────────────────────────────────
// SETUP: Replace the APP_ID below with your Atlas App Services App ID.
//        See implementation_plan.md for the one-time Atlas setup steps.
// ──────────────────────────────────────────────────────────────────────
import * as Realm from 'realm-web';

const APP_ID = process.env.REACT_APP_REALM_APP_ID || 'YOUR_APP_ID_HERE';
const app = new Realm.App({ id: APP_ID });

/**
 * Ensure we have an authenticated user (anonymous auth).
 * Re-uses the existing session if available.
 */
async function getUser() {
    if (app.currentUser) return app.currentUser;
    return app.logIn(Realm.Credentials.anonymous());
}

/**
 * Return a MongoDB collection handle you can call find() on.
 * @param {string} collectionName – e.g. 'stockData' or 'news'
 */
export async function getCollection(collectionName) {
    const user = await getUser();
    const mongo = user.mongoClient('mongodb-atlas');
    return mongo.db('Finnalyze').collection(collectionName);
}

// ─── Convenience query functions used by pages ───────────────────────

/**
 * Market page: return stock rows from stockData, excluding prediction='down'.
 */
export async function fetchMarketData() {
    const col = await getCollection('stockData');
    const docs = await col.find(
        { prediction: { $ne: 'down' } },
        { limit: 500 }
    );
    return docs.map((d) => ({
        symbol: d.code || d.symbol || String(d._id),
        name: d.name || '',
        price: Number(d.price || d.latest_price || 0),
        change: Number(d.change || 0),
        changePercent: Number(d.changePercent || d.change_percent || 0),
    }));
}

/**
 * News page: return articles from 'news' collection (falls back to stockData).
 */
export async function fetchNewsData() {
    // Try 'news' collection first
    try {
        const col = await getCollection('news');
        const docs = await col.find({ prediction: { $ne: 'down' } }, { limit: 500 });
        if (docs.length > 0) {
            return docs.map((d) => ({
                title: d.latest_headline || d.title || d.name || '',
                url: d.url || d.link || '#',
                source: d.source || d.source_name || '',
                published: d.updated_at || d.created_at || d.published || null,
                summary: d.latest_article || d.summary || d.description || '',
            }));
        }
    } catch (e) {
        console.debug('News collection query failed, trying stockData:', e?.message);
    }

    // Fallback: stockData
    const col = await getCollection('stockData');
    const docs = await col.find({ prediction: { $ne: 'down' } }, { limit: 500 });
    return docs.map((d) => ({
        title: d.latest_headline || d.title || d.name || '',
        url: d.url || d.link || '#',
        source: d.source || d.source_name || '',
        published: d.updated_at || d.created_at || d.published || null,
        summary: d.latest_article || d.summary || d.description || '',
    }));
}

/**
 * Sentiment page: return impact/prediction data, optionally filtered by company.
 */
export async function fetchSentimentData(company) {
    const col = await getCollection('stockData');
    let filter = {};
    if (company) {
        filter = {
            $or: [
                { code: company },
                { name: { $regex: company, $options: 'i' } },
            ],
        };
    }
    const docs = await col.find(filter, { limit: 1000 });
    return docs.map((d) => {
        let impact = 0;
        try { impact = Number(d.impact_score || 0) || 0; } catch { impact = 0; }
        return {
            code: d.code || d.symbol || String(d._id),
            name: d.name || '',
            prediction: d.prediction || null,
            impact_score: impact,
            latest_headline: d.latest_headline || d.title || null,
            latest_article: d.latest_article || d.article || d.summary || null,
        };
    });
}
